<template><div class="panel"><div class="section-head"><div><h2>系统参数</h2><p>敏感参数加密保存并以脱敏内容展示。</p></div><el-button v-if="auth.hasPermission('system:setting:create')" type="primary" @click="open()">新增参数</el-button></div><el-table :data="rows"><el-table-column prop="groupCode" label="分组"/><el-table-column prop="configKey" label="参数键"/><el-table-column prop="name" label="名称"/><el-table-column prop="configValue" label="值"/><el-table-column label="操作"><template #default="s"><el-button link type="primary" @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></el-table-column></el-table><el-dialog v-model="visible" :title="form.id?'编辑参数':'新增参数'"><el-form label-width="90px"><el-form-item label="分组"><el-input v-model="form.groupCode"/></el-form-item><el-form-item label="参数键"><el-input v-model="form.configKey"/></el-form-item><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item><el-form-item label="参数值"><el-input v-model="form.configValue" :placeholder="form.sensitive&&form.id?'留空保留原值':''"/></el-form-item><el-form-item label="敏感"><el-switch v-model="form.sensitive"/></el-form-item><el-form-item label="启用"><el-switch v-model="form.enabled"/></el-form-item></el-form><template #footer><el-button @click="visible=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import http from'../api/http';import{useAuthStore}from'../stores/auth';const auth=useAuthStore(),rows=ref([]),visible=ref(false),form=reactive({id:null,groupCode:'system',configKey:'',name:'',configValue:'',sensitive:false,enabled:true});async function load(){rows.value=(await http.get('/system/settings')).data}/** 打开参数窗口。 */function open(row){Object.assign(form,row?{...row,configValue:row.sensitive?'':row.configValue}:{id:null,groupCode:'system',configKey:'',name:'',configValue:'',sensitive:false,enabled:true});visible.value=true}/** 保存参数。 */async function save(){form.id?await http.put(`/system/settings/${form.id}`,form):await http.post('/system/settings',form);visible.value=false;await load();ElMessage.success('保存成功')}/** 删除参数。 */async function remove(row){await ElMessageBox.confirm(`确认删除参数「${row.configKey}」？`,'删除确认',{type:'warning'});await http.delete(`/system/settings/${row.id}`);await load()}onMounted(load)</script>
